base.script:
 sessionStorage.setItem("dc_lastRequestSentTime", new Date().getTime());
		if(!(/(MSIE|Trident)/.test(window.navigator.userAgent))){
			var bIsLocal = window.location.hostname === "localhost";
			var fnCreateComponent = function() {
				sap.ui.require(["sap/ui/core/ComponentContainer"], function(ComponentContainer) {
					new ComponentContainer({
						name: "com.sap.platformx",
						manifest: true,
						height: "100%",
						componentCreated: function(oParams) {
							sap.ui.getCore().loadLibrary("sap.ui.unified", { async: true });
							sap.ui.getCore().loadLibrary("sap.f", { async: true });
							sap.ui.getCore().loadLibrary("sap.uxap", { async: true });
							const spinner = document.getElementById("dc-loading-spinner");
							if (spinner) {
								spinner.remove();
							}
						}
					}).placeAt("content");
				});
			};
			sap.ui.getCore().attachInit(function() {
				if (bIsLocal) {
					// Skip preload loading for local development
					fnCreateComponent();
				} else {
					// Explicitly load Component-preload.js first to ensure manifest is cached
					var sPreloadUrl = sap.ui.require.toUrl("com/sap/platformx/Component-preload.js");
					var oScript = document.createElement("script");
					oScript.src = sPreloadUrl;
					oScript.onload = fnCreateComponent;
					document.head.appendChild(oScript);
				}
			});
		}else{
			sap.ui.getCore().attachInit(function() {
				sap.ui.getCore().loadLibrary("sap.m", { async: false });
				var oImage = new sap.m.Image({src:"images/ie_logo.png",width:"15rem"});
				var oIcon = new sap.ui.core.Icon({src:"sap-icon://message-information"}).addStyleClass("iconfontStyle");
				var oSubText = new sap.m.Text({text:"Browser not Supported"}).addStyleClass("subTextFontStyle");
				var oText = new sap.m.Text({text:"Use Microsoft Edge or other alternative browsers like Google Chrome, Mozilla Firefox, Opera, etc. "}).addStyleClass("textFontStyle");
				var oVBox = new sap.m.VBox({items:[oIcon, oSubText, oText], alignContent:"Center", alignItems:"Center"}).addStyleClass("innerContainerStyle");
				var oHBox = new sap.m.HBox({items:[oImage, oVBox]}).addStyleClass("containerStyle");
				oHBox.placeAt("content");
			});
		}
